    "3.G.1": {
        "domain": "G",
        "cluster": "Reason with shapes and their attributes",
        "description": "Understand that shapes in different categories (e.g., rhombuses, rectangles, and others) may share attributes (e.g., having four sides), and that the shared attributes can define a larger category (e.g., quadrilaterals).",
